1	const PROCESSING_FEE = 5;
2	const FIRST_INSURANCE_RATE = 0.1;
3	
4	const BASE_PREMIUMS: Record<string, number> = {
5	  sword: 100,
6	  amulet: 60,
7	  staff: 80,
8	  potion: 40,
9	  rune: 25,
10	  moonstone: 25,
11	};
12	
13	const COMPONENT_BLOCK_PREMIUM: Record<string, number> = {
14	  rune: 60,
15	  moonstone: 60,
16	};
17	
18	function calculateBasePremium(items: any[]): number {
19	  const countsByType: Record<string, number> = {};
20	  for (const item of items) {
21	    countsByType[item.type] = (countsByType[item.type] ?? 0) + 1;
22	  }
23	
24	  let total = 0;
25	  for (const type of Object.keys(countsByType)) {
26	    const count = countsByType[type];
27	    if (count === 3 && COMPONENT_BLOCK_PREMIUM[type] !== undefined) {
28	      total += COMPONENT_BLOCK_PREMIUM[type];
29	    } else {
30	      total += count * BASE_PREMIUMS[type];
31	    }
32	  }
33	  return total;
34	}
35	
36	function calculateItemSurcharges(items: any[]): number {
37	  let surcharges = 0;
38	  for (const item of items) {
39	    const itemBase = BASE_PREMIUMS[item.type];
40	    if (item.cursed) {
41	      surcharges += itemBase * 0.5;
42	    }
43	    if (item.enchantment >= 5) {
44	      surcharges += itemBase * 0.3;
45	    }
46	  }
47	  return surcharges;
48	}
49	
50	function calculatePremium(items: any[], customer: any): number {
51	  const basePremium = calculateBasePremium(items);
52	  const itemSurcharges = calculateItemSurcharges(items);
53	  const firstInsuranceSurcharge = basePremium * FIRST_INSURANCE_RATE;
54	  const loyaltyDiscount = customer.yearsWithMHPCO >= 2 ? basePremium * 0.2 : 0;
55	  return Math.ceil(basePremium + itemSurcharges + firstInsuranceSurcharge - loyaltyDiscount + PROCESSING_FEE);
56	}
57	
58	export function processScenario(scenario: any): unknown {
59	  const { customer } = scenario;
60	  const { items } = scenario.steps[0];
61	  const premium = calculatePremium(items, customer);
62	
63	  return { results: [{ premium }] };
64	}
